public class CreateUserService {
    public Map<String, String> execute(Map<String, String> data) {
        if (data.get("username") == null) {
            throw new RuntimeException("Username e obrigatorio");
        }
    }
}

String user = data.get("username");
String password = data.get("password");
Map<String, String> objectUser = new LinkedHashMap<>();
objectUser.put("user", user);
objectUser.put("password", password);

return objectUser;

