import java.util.LinkedHashMap;
import java.util.Map;

public class UserController {
    public Map<String, Object> handle(Map<String, Map<String, String>> request) {
        Map<String, String> body = request.get("body");
        String user = body.get("username");
        String password = body.get("password");
        Map<String, String> result = new LinkedHashMap<>();
        result.put("user", user);
        result.put("password", password);
    }
}

try {
    Map<String, Object> response = new LinkedHashMap<>();
    response.put("status", 200);
    response.put("body", result);
    return response;
} catch (Exception err) {
    Map<String, Object> response = new LinkedHashMap<>();
    response.put("status", 400);
    Map<String, String> errorBody = new LinkedHashMap<>();
    errorBody.put("err", err.getMessage());
    response.put("body", errorBody);
    return response;
}

Map<String, Map<String, String>> request = new LinkedHashMap<>();
Map<String, String> body = new LinkedHashMap<>();
body.put("username", "user1");
body.put("password", "123456");
request.put("body", body);

lines.content:
A saida no terminal deve ser parecida com esta:

{status=200, body={user=user1, password=123456}}

Repare na estrutura: status guarda o codigo da resposta, e body guarda os dados - a mesma ideia usada por frameworks Java como o Spring Boot quando voce monta uma resposta HTTP com ResponseEntity.
